import React from 'react';
import { Activity, Layers, Brain, BookText, Map as MapIcon } from 'lucide-react';
import { AppMode } from '../types';

interface HeaderProps {
  currentMode: AppMode;
  onModeChange: (mode: AppMode) => void;
}

const Header: React.FC<HeaderProps> = ({ currentMode, onModeChange }) => {
  const navItems = [
    { mode: AppMode.FLASHCARDS, label: 'Flashcards', icon: Layers },
    { mode: AppMode.ATLAS, label: 'Atlas', icon: MapIcon },
    { mode: AppMode.QUIZ, label: 'Exam', icon: Brain },
    { mode: AppMode.LIST, label: 'Index', icon: BookText },
  ];

  return (
    <header className="sticky top-0 z-[100] px-4 pt-6 pb-2 pointer-events-none">
      <div className="max-w-7xl mx-auto pointer-events-auto flex items-center justify-between">

          {/* Brand Section */}
          <div 
            className="flex items-center gap-4 cursor-pointer group select-none"
            onClick={() => onModeChange(AppMode.FLASHCARDS)}
          >
            <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center shadow-xl shadow-slate-200 text-white transition-transform group-hover:scale-105">
              <Activity size={24} className="text-rose-500" strokeWidth={3} />
            </div>

            <div className="flex flex-col justify-center">
              <div className="bg-slate-100 border border-slate-200 px-2 py-0.5 rounded-md w-fit mb-1">
                 <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em] block">Occupational Therapy</span>
              </div>
              <h1 className="text-xl font-bold text-slate-900 leading-none tracking-tight font-display">
                Anatomy <span className="text-slate-300">&</span> Physiology <span className="text-amber-400 font-black">OT</span>
              </h1>
            </div>
          </div>

          {/* Desktop Nav - Pill Design */}
          <nav className="hidden md:flex items-center gap-1 bg-slate-100/80 backdrop-blur-sm p-1.5 rounded-full border border-slate-200 shadow-sm">
            {navItems.map((item) => {
              const isActive = currentMode === item.mode;
              const Icon = item.icon;
              return (
                <button
                  key={item.mode}
                  onClick={() => onModeChange(item.mode)}
                  className={`relative px-6 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all duration-300 flex items-center gap-2 ${
                    isActive 
                      ? "text-slate-900 bg-white shadow-md transform scale-100" 
                      : "text-slate-400 hover:text-slate-600 hover:bg-slate-200/50"
                  }`}
                >
                  <Icon size={14} className={isActive ? 'text-rose-600' : 'opacity-70'} strokeWidth={3} />
                  <span>{item.label}</span>
                </button>
              );
            })}
          </nav>

          {/* Mobile Menu Button (Placeholder for functionality if needed later) */}
          <div className="md:hidden">
             <div className="w-10 h-10 bg-white rounded-xl border border-slate-200 flex items-center justify-center shadow-sm">
                <div className="flex flex-col gap-1">
                    <span className="w-4 h-0.5 bg-slate-800 rounded-full"></span>
                    <span className="w-4 h-0.5 bg-slate-800 rounded-full"></span>
                </div>
             </div>
          </div>

      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, Volume2, VolumeX, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  BookOpen, Repeat
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=80&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault)), [mistakesVault]);
  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakesVault.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    if (isShuffled) {
        // Simple deterministic shuffle based on length to keep it somewhat stable during re-renders unless length changes
        // In production, you'd want a more robust shuffle state
        return [...filtered].sort(() => Math.random() - 0.5);
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakesVault, isShuffled]);

  useEffect(() => {
    if (currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  useEffect(() => {
    if (currentIndex < activeData.length - 1) {
        const nextCard = activeData[currentIndex + 1];
        if (nextCard.questionImage) (new Image()).src = cleanImageUrl(nextCard.questionImage);
        if (nextCard.answerImage) (new Image()).src = cleanImageUrl(nextCard.answerImage);
    }
  }, [currentIndex, activeData]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const filterOptions: FilterOption[] = [
    { label: 'Mistakes Vault', subLabel: `${mistakesVault.length} Cards`, icon: AlertTriangle, isActive: showMistakesOnly, onClick: () => setShowMistakesOnly(!showMistakesOnly), colorTheme: 'amber' },
    { label: 'Visuals Only', subLabel: 'Diagrams', icon: ImageIcon, isActive: showImagesOnly, onClick: () => setShowImagesOnly(!showImagesOnly), colorTheme: 'indigo' }
  ];

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight">
                {showMistakesOnly ? "Vault Cleared" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all recorded mistakes." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-6 py-4">
        <div className="flex items-center gap-3">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`h-10 px-4 rounded-xl border transition-all flex items-center gap-2 text-xs font-black uppercase tracking-wider ${selectedCategories.length > 0 || showImagesOnly || showMistakesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'}`}
           >
             <Filter size={14} strokeWidth={3} />
             <span>Filter</span>
             {(selectedCategories.length > 0 || showImagesOnly || showMistakesOnly) && (
                 <span className="w-5 h-5 flex items-center justify-center bg-rose-500 text-white rounded-full text-[9px] font-black ml-1">
                    {[selectedCategories.length > 0, showImagesOnly, showMistakesOnly].filter(Boolean).length}
                 </span>
             )}
           </button>

           <div className="hidden md:flex flex-col justify-center px-2">
              <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-1.5">
                {showMistakesOnly ? <><AlertTriangle size={12} className="text-amber-500" /> Mistakes Vault</> : <><BookOpen size={12} /> Study Deck</>}
              </h2>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`p-2.5 rounded-xl border transition-all hover:bg-slate-50 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-500'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight size={18} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`p-2.5 rounded-xl border transition-all hover:bg-slate-50 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-500'}`}
             title="Shuffle Deck"
           >
             <Shuffle size={18} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-4 md:pb-8 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full group cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200 border-2 border-slate-100 p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar">
               {/* Front Header */}
               <div className="w-full flex justify-between items-start mb-4">
                   <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-300">
                     {frontContent.label}
                   </span>
                   {showMistakesOnly && (
                       <div className="flex items-center gap-1 text-[9px] font-black text-rose-500 uppercase tracking-widest bg-rose-50 px-2 py-1 rounded border border-rose-100">
                           <AlertTriangle size={10} /> Mistake
                       </div>
                   )}
               </div>

               {/* Front Body */}
               <div className="flex-1 flex flex-col items-center justify-center w-full py-4 space-y-6">
                 {frontContent.image && (
                   <div className="max-h-[40vh] w-full flex items-center justify-center rounded-2xl p-4 bg-slate-50 border border-slate-100">
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg mix-blend-multiply" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <h2 className={`text-xl md:text-3xl font-black leading-tight mb-6 text-slate-800 break-words w-full ${frontContent.text && frontContent.text.length > 100 ? 'md:text-2xl' : ''}`} dangerouslySetInnerHTML={{ __html: frontContent.text || '' }} />
               </div>

               {/* Front Footer */}
               <div className="w-full flex justify-between items-end mt-4" onClick={e => e.stopPropagation()}>
                 <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest truncate max-w-[70%] text-left">
                    {currentCard.category}
                 </div>
                 <div className="flex items-center gap-3">
                    {showMistakesOnly && !frontContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-4 bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-100 border border-emerald-200 transition-colors shadow-sm"
                        >
                            <CheckCircle2 size={20} strokeWidth={2.5} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, frontContent.text || '', '-front')}
                        className="p-4 bg-slate-50 rounded-full text-slate-400 hover:bg-rose-50 hover:text-rose-600 transition-colors"
                    >
                        {isSpeaking && speakingId?.endsWith('-front') ? <VolumeX size={24} /> : <Volume2 size={24} />}
                    </button>
                 </div>
               </div>
            </div>

            {/* BACK FACE */}
            <div className="absolute inset-0 backface-hidden rotate-y-180 bg-slate-900 rounded-[2.5rem] shadow-2xl p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar text-white">
               {/* Back Header */}
               <div className="w-full flex justify-between items-start mb-4">
                   <span className="text-[10px] font-black uppercase tracking-[0.3em] text-emerald-400">
                     {backContent.label}
                   </span>
               </div>

               {/* Back Body */}
               <div className="flex-1 flex flex-col items-center justify-center w-full py-4 space-y-6">
                 {backContent.image && (
                   <div className="max-h-[40vh] w-full flex items-center justify-center rounded-2xl p-4 bg-white/5 border border-white/10">
                     <img 
                       src={cleanImageUrl(backContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <p className={`text-xl md:text-3xl font-bold leading-relaxed mb-6 text-emerald-400 break-words w-full ${backContent.text && backContent.text.length > 100 ? 'md:text-2xl' : ''}`} dangerouslySetInnerHTML={{ __html: backContent.text || '' }} />

                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-6 bg-white/5 rounded-2xl border border-white/10 text-left mt-4">
                     <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-2">Clinical Note</span>
                     <p className="text-sm font-medium text-slate-300 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               {/* Back Footer */}
               <div className="w-full flex justify-between items-end mt-4" onClick={e => e.stopPropagation()}>
                 <div className="text-[10px] font-bold text-slate-600 uppercase tracking-widest truncate max-w-[70%] text-left">
                    {currentCard.category}
                 </div>
                 <div className="flex items-center gap-3">
                    {showMistakesOnly && !backContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="p-4 bg-emerald-900/50 text-emerald-400 rounded-full hover:bg-emerald-900 border border-emerald-800 transition-colors shadow-sm"
                        >
                            <CheckCircle2 size={24} strokeWidth={2.5} />
                        </button>
                    )}
                    <button 
                        onClick={(e) => handleSpeak(e, backContent.text || '', '-back')}
                        className="p-4 bg-white/10 rounded-full text-slate-400 hover:bg-white/20 hover:text-white transition-colors"
                    >
                        {isSpeaking && speakingId?.endsWith('-back') ? <VolumeX size={24} /> : <Volume2 size={24} />}
                    </button>
                 </div>
               </div>
            </div>

          </div>
        </div>
      </div>

      {/* Navigation - Bottom */}
      <div className="px-6 pb-28 md:pb-12 pt-4 flex justify-center gap-8 md:gap-12 items-center">
        <button 
          onClick={handlePrev} 
          disabled={currentIndex === 0}
          className="h-14 px-8 rounded-2xl bg-white border-2 border-slate-200 flex items-center gap-3 text-slate-600 disabled:opacity-40 disabled:cursor-not-allowed hover:border-slate-300 hover:bg-slate-50 transition-all shadow-sm active:translate-y-0.5 font-bold uppercase text-xs tracking-wider"
        >
          <ArrowLeft size={18} /> Previous
        </button>

        {/* Counter / Visual Cue */}
        <div className="flex flex-col items-center gap-1">
            <span className="text-xl font-black text-slate-900 font-display">{currentIndex + 1} <span className="text-slate-300 text-base font-bold">/ {activeData.length}</span></span>
        </div>

        <button 
          onClick={handleNext} 
          disabled={currentIndex === activeData.length - 1}
          className="h-14 px-10 rounded-2xl bg-slate-900 flex items-center gap-3 text-white disabled:opacity-40 disabled:cursor-not-allowed hover:bg-slate-800 transition-all shadow-lg hover:shadow-xl active:translate-y-0.5 font-bold uppercase text-xs tracking-wider"
        >
          Next <ArrowRight size={18} />
        </button>
      </div>

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Deck Filters"
      />
    </div>
  );
};

