// Robust Image Proxy for High Performance & Reliability
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Using wsrv.nl for reliable resizing, webp conversion, and caching
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=1200&q=82&output=webp&il`;
};

interface InteractiveAtlasProps {
  data: Question[];
}

