import React, { useState, useEffect, useRef, useCallback } from 'react';

type AudioType = 'question' | 'answer' | 'explanation' | 'generic';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);
  // CRITICAL FIX: Keep a reference to the utterance to prevent Garbage Collection in Chrome/Edge
  const utteranceRef = useRef<SpeechSynthesisUtterance | null>(null);

  const loadVoices = useCallback(() => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    let voices = window.speechSynthesis.getVoices();
    if (voices.length === 0) return;

    // Filter for English voices only
    const englishVoices = voices.filter(v => v.lang.startsWith('en'));

    // Scoring system to find the clearest/most natural voice
    const rankedVoices = englishVoices.sort((a, b) => {
        const getScore = (v: SpeechSynthesisVoice) => {
            let score = 0;
            const name = v.name.toLowerCase();
            // Premium/Natural voices (Edge/Azure/Chrome)
            if (name.includes('natural')) score += 100;
            if (name.includes('google') && name.includes('us english')) score += 90;
            if (name.includes('samantha')) score += 80;
            if (name.includes('daniel')) score += 75; 
            if (name.includes('zira')) score += 70;
            if (v.default) score += 50;
            return score;
        };
        return getScore(b) - getScore(a);
    });

    // Select the best voice
    setVoice(rankedVoices[0] || voices[0]);
  }, []);

  useEffect(() => {
    loadVoices();
    if (window.speechSynthesis && window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
    // Retry loading voices a few times to ensure they are available
    const timer = setTimeout(loadVoices, 500);
    return () => {
      clearTimeout(timer);
      cancel(); // Ensure cleanup on unmount
    };
  }, [loadVoices]);

  const cancel = useCallback(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      setActiveType(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
      utteranceRef.current = null;
    }
  }, []);

  const speak = useCallback((text: string, id: string, type: AudioType = 'generic', e?: React.MouseEvent | React.KeyboardEvent) => {
    if (e) e.stopPropagation();
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    // If currently speaking THIS ID, toggle it off
    if (speakingRef.current && activeUtteranceId.current === id) {
      cancel();
      return;
    }

    // Always cancel previous speech before starting new
    cancel();

    // ENHANCED MEDICAL PRONUNCIATION & CLEANING
    const cleanText = text
      .replace(/<[^>]*>/g, ' ') // Replace tags with space
      .replace(/\s+/g, ' ') // Collapse multiple spaces
      // Chemistry / Anatomy specific replacements
      .replace(/Ca2\+/g, 'calcium ions') 
      .replace(/Na\+/g, 'sodium ions')
      .replace(/K\+/g, 'potassium ions')
      .replace(/H\+/g, 'hydrogen ions')
      .replace(/Cl-/g, 'chloride ions')
      .replace(/\bATP\b/g, 'A T P')
      .replace(/\bDNA\b/g, 'D N A')
      .replace(/\bRNA\b/g, 'R N A')
      .replace(/\bCO2\b/g, 'C O 2')
      .replace(/\bO2\b/g, 'oxygen')
      .replace(/\bH2O\b/g, 'water')
      .replace(/°C/g, 'degrees Celsius')
      .replace(/µm/g, 'micrometers')
      .replace(/²/g, ' squared')
      .replace(/³/g, ' cubed')
      // Punctuation for pacing
      .replace(/[\(\[\{]/g, ', ') 
      .replace(/[\)\]\}]/g, ', ')
      .replace(/\//g, ' or ')
      .replace(/&/g, ' and ')
      .replace(/(\d+)\/(\d+)/g, '$1 out of $2') 
      .replace(/([.:;?!])/g, '$1 ')
      .trim();

    // Intelligent Chunking: Split by sentence boundaries to avoid timeouts
    const rawChunks = cleanText.match(/[^.!?]+[.!?]+(?=\s|$)|[^.!?]+$/g) || [cleanText];
    const chunks = rawChunks.map(c => c.trim()).filter(c => c.length > 0);

    if (chunks.length === 0) return;

    activeUtteranceId.current = id;
    speakingRef.current = true;
    setIsSpeaking(true);
    setSpeakingId(id);
    setActiveType(type);

    let currentChunkIndex = 0;

    const speakNextChunk = () => {
        if (currentChunkIndex >= chunks.length || !speakingRef.current) {
            setIsSpeaking(false);
            setSpeakingId(null);
            setActiveType(null);
            speakingRef.current = false;
            activeUtteranceId.current = null;
            utteranceRef.current = null;
            return;
        }

        const chunkText = chunks[currentChunkIndex];
        const utterance = new SpeechSynthesisUtterance(chunkText);

        // Prevent Garbage Collection
        utteranceRef.current = utterance;

        if (voice) {
            utterance.voice = voice;
            utterance.lang = voice.lang;
        } else {
            utterance.lang = 'en-US';
        }

        // TUNED FOR CLARITY
        utterance.rate = 0.9;  // Clear, deliberate speed
        utterance.pitch = 1.0; // Natural pitch
        utterance.volume = 1.0; // Max volume

        utterance.onend = () => {
            currentChunkIndex++;
            speakNextChunk();
        };

        utterance.onerror = (event) => {
            console.error("Speech Error:", event);
            // Even on error, try next chunk or reset
            if (event.error !== 'interrupted') {
                currentChunkIndex++;
                speakNextChunk();
            } else {
                setIsSpeaking(false);
                setSpeakingId(null);
            }
        };

        window.speechSynthesis.speak(utterance);
    };

    speakNextChunk();

  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, Volume2, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  RotateCcw, Info
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

// IMAGE SERVER / PROXY SETUP
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=80&output=webp&il`;
};

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Moved useMemo before useEffect to avoid "used before declaration" error
  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakesVault.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    if (isShuffled) {
        return [...filtered].sort(() => Math.random() - 0.5);
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakesVault, isShuffled]);

  useEffect(() => localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault)), [mistakesVault]);
  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  // Keyboard Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isFilterOpen) return;

      if (e.key === 'ArrowRight') {
        if (currentIndex < activeData.length - 1) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c + 1), 150);
        }
      } else if (e.key === 'ArrowLeft') {
        if (currentIndex > 0) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c - 1), 150);
        }
      } else if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        setIsFlipped(prev => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, activeData.length, isFilterOpen, cancel]); 

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  useEffect(() => {
    if (currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const filterOptions: FilterOption[] = [
    { label: 'Smart Review', subLabel: `${mistakesVault.length} Cards`, icon: AlertTriangle, isActive: showMistakesOnly, onClick: () => setShowMistakesOnly(!showMistakesOnly), colorTheme: 'amber' },
    { label: 'Visuals Only', subLabel: 'Diagrams', icon: ImageIcon, isActive: showImagesOnly, onClick: () => setShowImagesOnly(!showImagesOnly), colorTheme: 'indigo' }
  ];

  // Helper for dynamic text sizing
  const getTextSizeClass = (text: string = '') => {
    const len = text.length;
    if (len < 30) return 'text-3xl md:text-5xl';
    if (len < 80) return 'text-2xl md:text-4xl';
    if (len < 150) return 'text-xl md:text-3xl';
    if (len < 300) return 'text-lg md:text-2xl';
    return 'text-base md:text-xl';
  };

  // Content Refinement Helper
  const formatCardText = (text: string = '') => {
    if (!text) return '';
    return text
      .replace(/^Define the term:\s*/i, '')
      .replace(/^Anatomical term for:\s*/i, '')
      .replace(/^Define:\s*/i, '')
      .replace(/^Identify the\s+/i, '')
      .trim();
  };

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight font-display">
                {showMistakesOnly ? "Review Complete" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all items in your Smart Review list." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  // Pre-calculate formatted text for consistent sizing and display
  const frontDisplayText = formatCardText(frontContent.text);
  const backDisplayText = formatCardText(backContent.text);

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-6 py-6">
        <div className="flex items-center gap-4">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`w-12 h-12 rounded-2xl border transition-all flex items-center justify-center ${selectedCategories.length > 0 || showImagesOnly || showMistakesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter size={18} strokeWidth={2} />
           </button>

           <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-0.5 flex items-center gap-2">
                 {showMistakesOnly && <AlertTriangle size={10} className="text-amber-500" />} {showMistakesOnly ? 'Smart Review' : 'Study Deck'}
              </span>
              <span className="text-sm font-bold text-slate-900 font-display">Card {currentIndex + 1} <span className="text-slate-300 font-sans">of {activeData.length}</span></span>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`w-12 h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight size={18} strokeWidth={2} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`w-12 h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Shuffle Deck"
           >
             <Shuffle size={18} strokeWidth={2} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-4 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full max-h-[700px] cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2.5rem] shadow-card hover:shadow-card-hover border border-slate-100 p-8 md:p-12 flex flex-col items-center text-center overflow-y-auto custom-scrollbar group">
               {/* Front Header */}
               <div className="w-full flex justify-between items-start mb-6 shrink-0">
                   <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-300">
                     {frontContent.label}
                   </span>
                   {showMistakesOnly && (
                       <div className="flex items-center gap-1 text-[9px] font-black text-amber-500 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100">
                           <AlertTriangle size={10} /> Review Item
                       </div>
                   )}
               </div>

               {/* Front Body */}
               <div className="flex-1 flex flex-col items-center justify-center w-full py-2 space-y-6">
                 {frontContent.image && (
                   <div className="max-h-[35vh] w-full flex items-center justify-center rounded-2xl p-4 bg-slate-50/50 border border-slate-100">
                     <img 
                       src={cleanImageUrl(frontContent.image)} 
                       className="max-h-full max-w-full object-contain rounded-lg mix-blend-multiply" 
                       alt="Content" 
                     />
                   </div>
                 )}

                 <h2 
                    className={`font-bold leading-tight text-slate-800 break-words w-full font-display ${getTextSizeClass(frontDisplayText)}`} 
                    dangerouslySetInnerHTML={{ __html: frontDisplayText }} 
                 />

                 {/* Explanation displayed if this side is the Answer */}
                 {!frontContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-5 bg-amber-50/50 rounded-xl border border-amber-100 text-left mt-4 animate-in fade-in slide-in-from-bottom-2 relative shrink-0">
                     <div className="flex items-center gap-2 mb-2 text-amber-600/70">
                        <Info size={14} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Clinical Note</span>
                     </div>
                     <p className="text-sm font-medium text-slate-700 leading-relaxed font-sans" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
                 )}
               </div>

               {/* Front Footer */}
               <div className="w-full flex justify-between items-end mt-6 shrink-0" onClick={e => e.stopPropagation()}>
                 <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest truncate max-w-[70%] text-left">
                    {currentCard.category.split(':')[0]}
                 </div>

                 <div className="flex items-center gap-3">
                    {showMistakesOnly && !frontContent.isQuestion && (
                        <button 
                            onClick={(e) => handleResolveMistake(currentCard.id, e)}
                            className="w-10 h-10 flex items-center justify-center bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-100 border border-emerald-200 transition-colors shadow-sm"
                            title="Mark as Learned"
                        >
                            <CheckCircle2 size={18} strokeWidth={2.5} />
                        </button>
                    )}
                 </div>
               </div>

                {/* Audio Button - Floating */}
