                 {/* Explanation displayed if this side is the Answer */}
                 {!backContent.isQuestion && currentCard.explanation && (
                   <div className="w-full max-w-2xl p-6 bg-white/5 rounded-2xl border border-white/10 text-left mt-4 animate-in fade-in slide-in-from-bottom-2 shrink-0">
                     <div className="flex items-center gap-2 mb-2 text-slate-400">
                        <Info size={14} />
                        <span className="text-[10px] font-black uppercase tracking-widest">Clinical Note</span>
                     </div>
                     <p className="text-sm font-medium text-slate-300 leading-relaxed font-sans" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                   </div>
