                <ArrowUpDown size={16} />
            </button>
          </div>
        </div>
      </div>

      {/* Results Grid - content-visibility: auto speeds up rendering */}
      <div className="space-y-4 content-visibility-auto">
        {currentData.length > 0 ? (
          currentData.map((q) => (
            <div key={q.id} className={`bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row relative group ${mistakesVault.includes(q.id) ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}>
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden">
                   <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
                </div>
              )}
              <div className="p-6 md:p-8 flex-1">
                <div className="flex items-center justify-between mb-3 md:mb-4">
                  <span className="text-[9px] font-black uppercase text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 max-w-[70%] truncate">{q.category}</span>
                  <div className="flex items-center gap-2">
                    {/* Audio Button */}
                    <button 
                        onClick={(e) => handleSpeak(e, `${formatQuestionText(q.questionText)} ... Answer: ${q.answerText}`, q.id)}
                        className={`w-8 h-8 flex items-center justify-center rounded-lg transition-colors ${isSpeaking && speakingId === q.id ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-600'}`}
                        title="Listen"
                    >
                        {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                    </button>

                    {mistakesVault.includes(q.id) && (
                        <div className="flex items-center gap-2">
                            <span className="flex items-center gap-1 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100"><AlertTriangle size={10} /> Review</span>
                            <button 
                                onClick={(e) => removeMistake(q.id, e)}
                                className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-emerald-50 hover:text-emerald-600 text-slate-400 rounded-lg text-[10px] font-black uppercase tracking-wide transition-colors border border-slate-200"
                                title="Resolve this item"
                            >
                                <Check size={12} />
                            </button>
                        </div>
                    )}
                  </div>
                </div>
                <h3 className="text-lg md:text-xl font-black text-slate-800 leading-tight mb-3" dangerouslySetInnerHTML={{ __html: highlightText(formatQuestionText(q.questionText), debouncedSearch) }} />
                <div className="relative pl-4 md:pl-6 border-l-4 border-slate-200">
                  <p className="text-sm md:text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, debouncedSearch) }} />
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
                {showMistakesOnly ? "Review list is empty. Great job!" : showWrittenOnly ? "No written/concept questions found." : "No matching medical records found"}
            </p>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 mt-8 md:mt-12 mb-32 pb-safe">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowWrittenOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? clearAllMistakes : undefined}
        mainOptions={filterOptions}
        title="Library Filters"
      />
    </div>
  );
};

export default QuestionList;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Map as MapIcon, ChevronRight, Search, Maximize2, Minimize2, X, 
  Filter, AlertTriangle, CheckCircle2, ChevronDown, Layers, Scan,
  BrainCircuit, LayoutTemplate
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';
import Quiz from './Quiz'; // Reuse Quiz component for mini-sessions

// Robust Image Proxy for High Performance & Reliability
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  // Using wsrv.nl for reliable resizing, webp conversion, and caching
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=1200&q=82&output=webp&il`;
};

interface InteractiveAtlasProps {
  data: Question[];
}

const InteractiveAtlas: React.FC<InteractiveAtlasProps> = ({ data }) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isImageExpanded, setIsImageExpanded] = useState(false);
  const [isQuizMode, setIsQuizMode] = useState(false);

  const [search, setSearch] = useState('');
  const [visibleLimit, setVisibleLimit] = useState(24);

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  // Mistakes Vault Integration
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently remove all diagrams from your mistakes list?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Data Processing: Group questions by Image URL
  const atlasItems = useMemo(() => {
    const imagesMap = new Map<string, Question[]>();

    data.forEach(q => {
      const url = q.questionImage || q.answerImage;
      if (url) {
        if (!imagesMap.has(url)) imagesMap.set(url, []);
        imagesMap.get(url)?.push(q);
      }
    });

    let items = Array.from(imagesMap.entries()).map(([url, questions]) => ({
      url,
      category: questions[0].category,
      related: questions,
      // Enhanced title cleaning
      title: questions[0].questionText
        .replace(/^In the diagram,?\s*/i, '')
        .replace(/^Identify the\s+/i, '')
        .replace(/^Where is the\s+/i, '')
        .replace(/\??$/i, '')
        .trim(),
      hasMistake: questions.some(q => mistakesVault.includes(q.id))
    }));

    // Filtering
    if (showMistakesOnly) items = items.filter(item => item.hasMistake);
    if (selectedCategories.length > 0) items = items.filter(item => selectedCategories.includes(item.category));

    if (search.trim()) {
        const term = search.toLowerCase();
        items = items.filter(item => 
            item.category.toLowerCase().includes(term) || 
            item.related.some(r => r.questionText.toLowerCase().includes(term)) ||
            item.related.some(r => r.answerText.toLowerCase().includes(term))
        );
    }

    return items;
  }, [data, search, showMistakesOnly, selectedCategories, mistakesVault]);

  useEffect(() => {
    setVisibleLimit(24);
  }, [search, showMistakesOnly, selectedCategories]);

  // Close quiz/reset when image changes
  useEffect(() => {
    setIsQuizMode(false);
    setIsImageExpanded(false);
  }, [selectedImage]);

  const activeEntry = useMemo(() => atlasItems.find(i => i.url === selectedImage), [atlasItems, selectedImage]);
  const visibleItems = atlasItems.slice(0, visibleLimit);

  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-slate-50/50 relative">

      {/* 1. Sticky Header Control Bar */}
      <div className="px-4 py-4 md:px-8 md:py-6 sticky top-0 z-20 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm">
        <div className="max-w-7xl mx-auto flex gap-3 md:gap-4 items-center">

            {/* Search Input */}
            <div className="flex-1 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Search className="text-slate-400 group-focus-within:text-rose-500 transition-colors" size={18} />
                </div>
                <input 
                    type="text" 
                    placeholder={showMistakesOnly ? "Search errors in diagrams..." : "Search anatomical structures..."} 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
                />
            </div>

            {/* Filter Toggle */}
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`h-[46px] px-4 md:px-6 rounded-xl border transition-all flex items-center gap-2 font-bold text-xs uppercase tracking-wider ${
                    selectedCategories.length > 0 || showMistakesOnly 
                    ? 'bg-rose-50 border-rose-200 text-rose-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                }`}
            >
                <Filter size={16} />
                <span className="hidden md:inline">Filters</span>
                {(selectedCategories.length > 0 || showMistakesOnly) && (
                    <span className="flex h-5 w-5 items-center justify-center rounded-full bg-rose-600 text-[9px] text-white ml-1">
                        {[selectedCategories.length > 0, showMistakesOnly].filter(Boolean).length}
                    </span>
                )}
            </button>
        </div>

        {/* Diagnostic Mode Banner */}
        {showMistakesOnly && (
            <div className="max-w-7xl mx-auto mt-3 animate-in slide-in-from-top-2 fade-in">
                <div className="bg-amber-50 border border-amber-100 rounded-lg px-4 py-2 flex items-center justify-between text-amber-800 shadow-sm">
                    <div className="flex items-center gap-2">
                        <AlertTriangle size={16} className="text-amber-600" />
                        <span className="text-xs font-bold uppercase tracking-wide">Diagnostic Mode Active</span>
                    </div>
                    <span className="text-[10px] font-bold opacity-70">{atlasItems.length} Diagrams Found</span>
                </div>
            </div>
        )}
      </div>

      {/* 2. Main Content Grid */}
      <div className="flex-1 overflow-y-auto px-4 md:px-8 py-6 custom-scrollbar scroll-smooth">
        <div className="max-w-7xl mx-auto pb-32">
            {atlasItems.length > 0 ? (
                <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 content-visibility-auto">
                    {visibleItems.map((item, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => setSelectedImage(item.url)}
                            className="group cursor-pointer bg-white rounded-2xl border border-slate-100 shadow-card hover:shadow-card-hover hover:-translate-y-1 transition-all duration-300 flex flex-col overflow-hidden relative"
                        >
                            {/* Card Image */}
                            <div className="aspect-[4/3] bg-slate-50 relative overflow-hidden flex items-center justify-center p-4 border-b border-slate-50">
                                <img 
