                                </div>

                                <div className="mt-4 pt-3 border-t border-slate-50 flex items-center justify-between text-slate-400">
                                    <span className="text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5">
                                        <Layers size={14} className="text-slate-300" /> {item.related.length} Features
                                    </span>
                                    <ChevronRight size={14} className="group-hover:translate-x-1 transition-transform text-rose-300" />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Pagination Button */}
                {visibleLimit < atlasItems.length && (
                    <div className="mt-12 flex justify-center">
                        <button 
                            onClick={() => setVisibleLimit(prev => prev + 24)}
