                    <MapIcon size={48} className="text-slate-300" strokeWidth={1.5} />
                    <p className="font-bold text-slate-400">No Atlas Entries Found</p>
                </div>
            )}
        </div>
      </div>

      {/* 3. Detailed View Modal - Split Screen */}
      {activeEntry && (
        <div className="fixed inset-0 z-[100] flex flex-col md:flex-row bg-slate-950/95 backdrop-blur-xl animate-in fade-in duration-300">

          <button 
            onClick={() => setSelectedImage(null)} 
            className="absolute top-4 right-4 z-[120] p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all backdrop-blur-md border border-white/10 group"
          >
            <X size={20} className="group-hover:rotate-90 transition-transform" />
          </button>

          {/* Left Panel: Image (Responsive sizing based on expansion) */}
          <div className={`${isImageExpanded ? 'w-full h-full' : 'h-[40vh] md:h-full md:flex-[1.6]'} bg-slate-900 relative flex items-center justify-center p-4 md:p-12 overflow-hidden shadow-2xl transition-all duration-500`}>
            <div className="absolute inset-0 bg-grid-pattern opacity-5 pointer-events-none"></div>
            <img 
                src={cleanImageUrl(activeEntry.url)} 
                className="max-w-full max-h-full object-contain rounded-lg shadow-2xl" 
                alt="Active Diagram" 
            />

            {/* View Controls */}
            <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2">
                <button 
                    onClick={() => setIsImageExpanded(!isImageExpanded)}
                    className="bg-black/60 text-white/90 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest backdrop-blur-md flex items-center gap-2 border border-white/10 hover:bg-white/20 transition-all"
