                <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar space-y-4 bg-slate-50/50 pb-safe">
                {activeEntry.related.map((point, pIdx) => {
                    const isMistake = mistakesVault.includes(point.id);
                    return (
                        <div key={pIdx} className={`relative p-5 rounded-2xl bg-white border transition-all duration-300 ${isMistake ? 'border-amber-200 ring-1 ring-amber-100 shadow-sm' : 'border-slate-100 hover:border-slate-200 hover:shadow-sm'}`}>
                            <div className="flex justify-between items-start mb-2">
                                <div className="flex items-center gap-3">
                                    <div className={`flex items-center justify-center w-6 h-6 rounded-full text-[10px] font-bold border ${isMistake ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                                        {pIdx + 1}
                                    </div>
                                    <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Point of Interest</span>
                                </div>

                                {isMistake && (
                                    <button 
                                        onClick={(e) => handleResolveMistake(point.id, e)}
                                        className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 text-emerald-700 rounded-lg text-[10px] font-black uppercase tracking-wider hover:bg-emerald-100 transition-colors border border-emerald-100"
