import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertTriangle, Shuffle, Check, Volume2, RotateCcw,
  Monitor, Trophy
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';

// Enhanced Image Handling
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const formatOptionText = (text: string) => {
  return text.replace(/^(Option|Part)\s+/i, '').trim();
};

// Text Cleaning Helper
const formatQuestionText = (text: string) => {
  if (!text) return '';
  return text
    .replace(/^Define the term:\s*/i, '')
    .replace(/^Anatomical term for:\s*/i, '')
    .replace(/^Define:\s*/i, '')
    .replace(/^Identify the\s+/i, '')
    .replace(/^In the diagram,?\s*/i, '')
    .trim();
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader }) => {
  const savedState = useMemo(() => {
    try {
      const saved = localStorage.getItem('OT_QUIZ_SESSION_V5');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  }, []);

  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>(savedState?.view || 'setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>(savedState?.questions || []);
  const [currentQIndex, setCurrentQIndex] = useState(savedState?.currentQIndex || 0);
  const [timeLeft, setTimeLeft] = useState(savedState?.timeLeft || 0);
  const [imgError, setImgError] = useState(false);

  // Setup State
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>(savedState?.mode || 'exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true); 
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel } = useSpeech();
  const questionRef = useRef<HTMLDivElement>(null);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    if (view === 'playing' || view === 'results' || view === 'review') {
      localStorage.setItem('OT_QUIZ_SESSION_V5', JSON.stringify({
        view, questions, currentQIndex, timeLeft, mode
      }));
    } else {
      localStorage.removeItem('OT_QUIZ_SESSION_V5');
    }
  }, [view, questions, currentQIndex, timeLeft, mode]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      toggleHeader?.(false);
    } else {
      toggleHeader?.(true);
    }
  }, [view, toggleHeader]);

  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth < 1024) {
            setIsSidebarOpen(false);
        } else {
            setIsSidebarOpen(true);
        }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); // Init
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); 
    if (questionRef.current) {
        questionRef.current.scrollTop = 0;
    }
  }, [currentQIndex, view]);

  useEffect(() => {
    if (view === 'playing' && questions.length > 0 && currentQIndex < questions.length - 1) {
        const nextQ = questions[currentQIndex + 1];
        if (nextQ.data.questionImage) {
            const img = new Image();
            img.src = cleanImageUrl(nextQ.data.questionImage);
        }
    }
  }, [currentQIndex, questions, view]);

  // NEW: Keyboard Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (view !== 'playing') return;

      if (e.key === 'ArrowLeft') {
        if (currentQIndex > 0) {
            e.preventDefault();
            setCurrentQIndex(prev => prev - 1);
            setImgError(false);
        }
      } else if (e.key === 'ArrowRight') {
        if (currentQIndex < questions.length - 1) {
            e.preventDefault();
            setCurrentQIndex(prev => prev + 1);
            setImgError(false);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [view, currentQIndex, questions.length]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length > 0 ? [...q.options] : [q.answerText];

      // AUTO-GENERATE DISTRACTORS if missing options
      // This mimics the logic in data_ch1.ts but does it globally for safety
      if (finalOptions.length < 2) {
         // This is a failsafe. In a real app, you'd want better distractors.
         finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not shown"];
      }

      // Shuffle options
      finalOptions.sort(() => Math.random() - 0.5);

      return {
        id: q.id, 
        data: q,
        options: finalOptions,
        correctOption: q.answerText, 
        userAnswer: null, 
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startSession = () => {
    let pool = data;

    if (mode === 'mistakes') {
      pool = pool.filter(q => mistakesVault.includes(q.id));
    }
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);
    const preparedQuestions = prepareQuestions(finalPool);

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    cancel();
    setView('results');
  };

  const saveAndExit = (resolveCorrect: boolean) => {
    const wrongIds = questions.filter(q => q.userAnswer !== q.correctOption).map(q => q.id);
    const correctIds = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);

    setMistakesVault(prev => {
        let next = [...prev];
        if (wrongIds.length > 0) next = [...next, ...wrongIds];
        if (resolveCorrect) next = next.filter(id => !correctIds.includes(id));
        return Array.from(new Set(next));
    });

    localStorage.removeItem('OT_QUIZ_SESSION_V5');
    setView('setup');
    toggleHeader?.(true);
  };

  const retrySession = () => {
    const resetQuestions = questions.map(q => ({...q, userAnswer: null, isFlagged: false}));
    const reshuffled = [...resetQuestions].sort(() => Math.random() - 0.5);
    setQuestions(reshuffled);
    setCurrentQIndex(0);
    setTimeLeft(reshuffled.length * 60);
    setView('playing');
    toggleHeader?.(false);
  };

  const retryIncorrectOnly = () => {
    const wrongQuestions = questions
        .filter(q => q.userAnswer !== q.correctOption)
        .map(q => ({...q, userAnswer: null, isFlagged: false}));

    if (wrongQuestions.length === 0) return;

    setQuestions(wrongQuestions.sort(() => Math.random() - 0.5));
    setCurrentQIndex(0);
    setTimeLeft(wrongQuestions.length * 60);
    setView('playing');
    toggleHeader?.(false);
  };

  const exitQuiz = () => {
    if (confirm("End current exam session? Progress will be lost.")) {
      cancel();
      localStorage.removeItem('OT_QUIZ_SESSION_V5');
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Mode',
        icon: ImageIcon,
        isActive: showDiagramsOnly,
        onClick: () => setShowDiagramsOnly(!showDiagramsOnly),
        colorTheme: 'indigo'
    }
  ];

  // --- VIEW: SETUP ---
  if (view === 'setup') {
    let filteredPool = data;
    if (mode === 'mistakes') filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    const maxQuestions = filteredPool.length;

    if (questionCount > maxQuestions && maxQuestions > 0) setQuestionCount(maxQuestions);

    return (
      <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar relative">
          <div className="min-h-full flex flex-col items-center justify-center p-4 pb-32 md:pb-10">
             <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-200/50 overflow-hidden animate-in zoom-in-95 duration-500">
                {/* Header */}
                <div className="bg-slate-900 p-8 md:p-10 text-white relative overflow-hidden">
                    <div className="absolute top-[-20%] right-[-10%] opacity-10">
                        <Monitor size={200} />
                    </div>
                    <h2 className="text-2xl md:text-3xl font-display font-bold tracking-tight mb-2">Exam Configuration</h2>
                    <p className="text-slate-400 text-sm font-medium">Occupational Therapy Department</p>
                </div>

                <div className="p-6 md:p-10 space-y-8">
                    {/* Mode Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {[
                        { id: 'exam', label: 'University Exam', sub: 'Timed • No Hints', icon: Clock, color: 'rose' },
                        { id: 'practice', label: 'Study Mode', sub: 'Instant Feedback', icon: Zap, color: 'blue' },
                        { id: 'mistakes', label: 'Error Vault', sub: `${mistakesVault.length} items`, icon: AlertTriangle, color: 'amber' }
                    ].map((m) => (
                        <button 
                        key={m.id}
                        onClick={() => setMode(m.id as any)}
                        className={`p-5 rounded-2xl border-2 transition-all text-left flex flex-col gap-3 group relative overflow-hidden ${mode === m.id 
                            ? `border-${m.color}-500 bg-${m.color}-50 text-${m.color}-900` 
                            : 'border-slate-100 hover:border-slate-300 text-slate-500 hover:bg-slate-50'}`}
                        >
                            <div className={`p-2.5 rounded-xl w-fit ${mode === m.id ? `bg-${m.color}-200 text-${m.color}-700` : 'bg-slate-100 group-hover:bg-slate-200'}`}>
                                <m.icon size={20} />
                            </div>
                            <div>
                                <span className="block font-bold text-sm">{m.label}</span>
                                <span className="text-[10px] font-bold uppercase opacity-60 tracking-wider">{m.sub}</span>
                            </div>
                        </button>
                    ))}
                    </div>

                    <div className="space-y-6 border-t border-slate-100 pt-6">
                        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                            <button 
                                onClick={() => setIsBankModalOpen(true)}
                                className={`flex-1 w-full p-4 rounded-xl border-2 flex items-center justify-between transition-all ${selectedCategories.length > 0 ? 'border-slate-800 bg-slate-800 text-white' : 'border-slate-200 hover:border-slate-300 text-slate-600 hover:bg-slate-50'}`}
                            >
                                <div className="flex items-center gap-3">
                                    <List size={18} />
                                    <div className="text-left">
                                        <span className="block text-[10px] font-black uppercase tracking-widest opacity-70">Content Source</span>
                                        <span className="block text-sm font-bold truncate max-w-[200px]">
                                            {selectedCategories.length === 0 ? "All Chapters (Comprehensive)" : `${selectedCategories.length} Modules Selected`}
                                        </span>
                                    </div>
                                </div>
                                <ChevronRight size={16} />
                            </button>

                            <div className="flex-1 w-full space-y-3 bg-slate-50 p-4 rounded-xl border border-slate-200">
                                <div className="flex justify-between text-xs font-bold text-slate-500 uppercase tracking-widest px-1">
                                    <span>Question Limit</span>
                                    <span className="text-slate-900">{questionCount} / {maxQuestions}</span>
                                </div>
                                <input 
                                    type="range" 
                                    min="1" 
                                    max={maxQuestions || 1} 
                                    value={questionCount}
                                    disabled={maxQuestions === 0}
                                    onChange={(e) => setQuestionCount(Number(e.target.value))}
                                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900"
                                />
                            </div>
                        </div>
                    </div>

                    <button 
                    onClick={startSession}
                    disabled={maxQuestions === 0}
                    className="w-full py-5 bg-slate-900 hover:bg-rose-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl hover:shadow-2xl transition-all hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"
                    >
                    <span>Start Examination</span>
                    <ChevronRight size={18} />
                    </button>
                </div>
             </div>
          </div>

          <FilterModal
            isOpen={isBankModalOpen}
            onClose={() => setIsBankModalOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setShowDiagramsOnly(false); }}
            mainOptions={filterOptions}
            title="Curriculum Selection"
        />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f1f5f9] font-sans text-slate-900">

        {/* Top Information Bar */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shadow-sm shrink-0 z-30">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-slate-900 text-white rounded-lg flex items-center justify-center font-black text-xl">
                    OT
                </div>
                <div className="hidden md:block">
                    <h1 className="text-sm font-bold text-slate-900 leading-tight">Anatomy & Physiology</h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{isPracticeMode ? 'Formative Assessment' : 'Summative Exam'}</p>
                </div>
            </div>

            <div className="flex items-center gap-4 md:gap-6">
                {mode === 'exam' ? (
                    <div className={`flex items-center gap-2 px-4 py-2 rounded-lg font-mono font-bold text-lg border ${timeLeft < 60 ? 'bg-rose-50 text-rose-600 border-rose-200 animate-pulse' : 'bg-slate-50 text-slate-700 border-slate-200'}`}>
                        <Clock size={18} /> {formatTime(timeLeft)}
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <span className="px-3 py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-lg text-xs font-bold flex items-center gap-1.5"><CheckCircle2 size={14} /> {questions.filter(q => q.userAnswer === q.correctOption).length}</span>
                        <span className="px-3 py-1.5 bg-rose-50 text-rose-700 border border-rose-200 rounded-lg text-xs font-bold flex items-center gap-1.5"><X size={14} /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</span>
                    </div>
                )}

                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2.5 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors lg:hidden shadow-sm">
                    <LayoutGrid size={20} className="text-slate-600" />
                </button>
            </div>
        </header>

        <div className="flex-1 flex overflow-hidden relative">

            {/* Main Question Paper */}
            <main className="flex-1 flex flex-col relative min-w-0">
                {/* Progress Strip */}
                <div className="h-1 bg-slate-200 w-full">
                    <div 
                        className="h-full bg-rose-500 transition-all duration-300" 
                        style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                    />
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={questionRef}>
                    <div className="max-w-4xl mx-auto bg-white min-h-[500px] shadow-sm border border-slate-200 rounded-2xl overflow-hidden">

                        {/* Question Header */}
                        <div className="bg-slate-50/80 border-b border-slate-100 p-6 flex justify-between items-start">
                            <div className="flex flex-col gap-1.5 pr-4">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Question {currentQIndex + 1} of {questions.length}</span>
                                <span className="text-xs font-bold text-slate-600 bg-white border border-slate-200 px-3 py-1 rounded-md w-fit max-w-[200px] truncate">{currentQ.data.category}</span>
                            </div>
                            <div className="flex gap-2 shrink-0">
                                <button 
                                    onClick={() => setQuestions(prev => {
                                        const c = [...prev];
                                        c[currentQIndex].isFlagged = !c[currentQIndex].isFlagged;
                                        return c;
                                    })}
                                    className={`p-2.5 rounded-lg border transition-all ${currentQ.isFlagged ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                                    title="Mark for Review"
                                >
                                    <Flag size={18} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                                </button>
                                <button 
                                    onClick={() => speak(currentQ.data.questionText, currentQ.id)}
                                    className={`p-2.5 rounded-lg border transition-all ${isSpeaking ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}
                                >
                                    <Volume2 size={18} />
                                </button>
                            </div>
                        </div>

                        <div className="p-6 md:p-12 space-y-8">
                            {/* Stem */}
                            <h2 className="text-xl md:text-2xl font-display font-medium text-slate-900 leading-relaxed text-balance">
                                <span dangerouslySetInnerHTML={{ __html: formatQuestionText(currentQ.data.questionText) }} />
                            </h2>

                            {/* Image */}
                            {currentQ.data.questionImage && !imgError && (
                                <div className="border border-slate-100 rounded-xl p-4 bg-slate-50 flex justify-center">
                                    <img 
                                        src={cleanImageUrl(currentQ.data.questionImage)} 
                                        alt="Clinical Figure" 
                                        className="max-h-[40vh] w-auto object-contain rounded-lg shadow-sm"
                                        onError={() => setImgError(true)}
                                    />
                                </div>
                            )}

                            {/* Options */}
                            <div className="space-y-3">
                                {currentQ.options.map((opt, i) => {
                                    const letter = String.fromCharCode(65 + i);
                                    const isSelected = currentQ.userAnswer === opt;
                                    const isCorrect = isPracticeMode && currentQ.userAnswer && opt === currentQ.correctOption;
                                    const isWrong = isPracticeMode && currentQ.userAnswer && isSelected && opt !== currentQ.correctOption;
                                    const showAnswer = isPracticeMode && currentQ.userAnswer;

                                    let containerStyle = "border-slate-200 hover:border-slate-300 hover:bg-slate-50 cursor-pointer";
                                    let circleStyle = "border-slate-300 text-slate-500 bg-white";

                                    if (showAnswer) {
                                        if (isCorrect) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/50 cursor-default ring-1 ring-emerald-500";
                                            circleStyle = "bg-emerald-500 border-emerald-500 text-white";
                                        } else if (isWrong) {
                                            containerStyle = "border-rose-500 bg-rose-50/50 cursor-default ring-1 ring-rose-500";
                                            circleStyle = "bg-rose-500 border-rose-500 text-white";
                                        } else if (opt === currentQ.correctOption) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/20 cursor-default"; 
                                            circleStyle = "border-emerald-500 text-emerald-600 bg-emerald-50";
                                        } else {
                                            containerStyle = "border-slate-100 text-slate-400 cursor-default opacity-60";
                                        }
                                    } else if (isSelected) {
                                        containerStyle = "border-slate-900 bg-slate-50 shadow-md ring-1 ring-slate-900";
                                        circleStyle = "bg-slate-900 border-slate-900 text-white";
                                    }

                                    return (
                                        <div 
                                            key={i}
                                            onClick={() => {
                                                if (showAnswer) return;
                                                setQuestions(prev => {
                                                    const c = [...prev];
                                                    c[currentQIndex].userAnswer = opt;
                                                    return c;
                                                });
                                            }}
                                            className={`group relative flex items-center gap-4 p-4 rounded-xl border-2 transition-all duration-200 ${containerStyle}`}
                                        >
                                            <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center text-sm font-bold shrink-0 transition-colors ${circleStyle}`}>
                                                {showAnswer && isCorrect ? <Check size={16} /> : showAnswer && isWrong ? <X size={16} /> : letter}
                                            </div>
                                            <div className="flex-1 text-sm md:text-base font-medium leading-relaxed" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Explanation (Practice Mode) */}
                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-6 rounded-xl border text-sm leading-relaxed animate-in fade-in slide-in-from-top-2 shadow-sm ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-slate-50 border-slate-200 text-slate-800'}`}>
                                    <h4 className="font-bold uppercase tracking-widest text-xs mb-2 opacity-70 flex items-center gap-2">
                                        {currentQ.userAnswer === currentQ.correctOption ? <CheckCircle2 size={16} /> : <AlertTriangle size={16} />}
                                        {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                    </h4>
                                    <p dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "No additional clinical notes available." }} />
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Controls */}
                <div className="bg-white border-t border-slate-200 p-4 md:px-8 flex justify-between items-center shadow-[0_-4px_20px_-5px_rgba(0,0,0,0.05)] z-20">
                    <button 
                        onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))}
                        disabled={currentQIndex === 0}
                        className="flex items-center gap-2 px-6 py-3 rounded-xl font-bold text-xs uppercase tracking-widest text-slate-600 hover:bg-slate-50 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                    >
                        <ChevronLeft size={16} /> Previous
                    </button>

                    <button 
                        onClick={() => {
                            if (currentQIndex === questions.length - 1) {
                                handleFinish();
                            } else {
                                setCurrentQIndex(prev => prev + 1);
                                setImgError(false);
                            }
                        }}
                        className="flex items-center gap-2 px-8 py-3 rounded-xl font-bold text-xs uppercase tracking-widest bg-slate-900 text-white hover:bg-rose-600 shadow-lg shadow-slate-200 hover:shadow-rose-100 transition-all hover:-translate-y-0.5 active:translate-y-0"
                    >
                        {currentQIndex === questions.length - 1 ? 'Submit Exam' : 'Next Question'} 
                        {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}
                    </button>
                </div>
            </main>

            {/* Sidebar (Question Palette) */}
            <aside className={`bg-white border-l border-slate-200 w-full md:w-80 flex-col shrink-0 transition-transform duration-300 absolute lg:relative inset-y-0 right-0 z-40 shadow-2xl lg:shadow-none ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full lg:hidden'} flex`}>
                <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-slate-50/50">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-500">Question Palette</h3>
                    <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 p-2 hover:bg-slate-200 rounded-full"><X size={20} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-5 custom-scrollbar bg-slate-50/30">
                    <div className="grid grid-cols-5 gap-2.5">
                        {questions.map((q, i) => {
                            let style = "bg-white border-slate-200 text-slate-500 hover:border-slate-300 shadow-sm";
                            if (currentQIndex === i) style = "bg-slate-800 border-slate-800 text-white ring-2 ring-slate-200 shadow-md transform scale-105 z-10";
                            else if (q.isFlagged) style = "bg-amber-50 border-amber-400 text-amber-700";
                            else if (q.userAnswer) style = "bg-slate-100 border-slate-300 text-slate-900 font-bold";

                            return (
                                <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }}
                                    className={`aspect-square rounded-lg flex items-center justify-center text-xs font-medium border-2 transition-all relative group ${style}`}
                                >
                                    {i + 1}
                                    {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-2 h-2 bg-amber-500 rounded-full border border-white"></div>}
                                </button>
                            )
                        })}
                    </div>
                </div>

                <div className="p-6 border-t border-slate-200 bg-white space-y-4">
                    <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-400">
                        <span className="flex items-center gap-2"><div className="w-2 h-2 bg-slate-800 rounded-full"></div> Current</span>
                        <span className="flex items-center gap-2"><div className="w-2 h-2 bg-slate-200 rounded-full border border-slate-300"></div> Done</span>
                        <span className="flex items-center gap-2"><div className="w-2 h-2 bg-amber-400 rounded-full"></div> Flag</span>
                    </div>
                    <button onClick={exitQuiz} className="w-full py-3 border border-rose-100 bg-rose-50 text-rose-600 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-rose-100 transition-colors">
                        Abort Session
                    </button>
                </div>
            </aside>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Score Card) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
        <div className="h-full bg-slate-100 flex items-center justify-center p-4 overflow-y-auto custom-scrollbar">
            <div className="bg-white max-w-2xl w-full rounded-[2rem] shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500 relative">
                <div className="bg-slate-900 p-10 text-center text-white relative overflow-hidden">
                    {/* Confetti-like effect if high score */}
                    {percentage >= 80 && (
                        <div className="absolute inset-0 pointer-events-none opacity-20 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PGNpcmNsZSBjeD0iMiIgY3k9IjIiIHI9IjIiIGZpbGw9IiNmZmYiLz48L3N2Zz4=')]"></div>
                    )}

                    <div className="relative z-10">
                        <div className="w-16 h-16 bg-white/10 rounded-2xl mx-auto mb-4 flex items-center justify-center backdrop-blur-md border border-white/10">
                            {percentage >= 70 ? <Trophy size={32} className="text-emerald-400" /> : <AlertTriangle size={32} className="text-rose-400" />}
                        </div>
                        <h2 className="text-3xl font-display font-bold mb-2">Examination Report</h2>
                        <p className="text-slate-400 uppercase tracking-widest text-xs font-bold">Session ID: OT-{Date.now().toString().slice(-6)}</p>
                    </div>
                </div>

                <div className="p-8 md:p-12 space-y-10 text-center">
                    <div className="flex justify-center items-center gap-12">
                        <div className="text-center">
                            <span className="block text-6xl font-black text-slate-900 mb-2 tracking-tighter">{percentage}%</span>
                            <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Final Grade</span>
                        </div>
                        <div className="w-px h-20 bg-slate-100"></div>
                        <div className="text-center">
                            <span className="block text-6xl font-black text-slate-900 mb-2 tracking-tighter">{score}</span>
                            <span className="text-xs font-bold uppercase tracking-widest text-slate-400">Correct Answers</span>
                        </div>
                    </div>

                    <div className={`p-6 rounded-2xl border text-left ${percentage >= 70 ? 'bg-emerald-50 border-emerald-100' : 'bg-rose-50 border-rose-100'}`}>
                        <h4 className={`font-bold text-sm uppercase tracking-wider mb-2 flex items-center gap-2 ${percentage >= 70 ? 'text-emerald-800' : 'text-rose-800'}`}>
                            {percentage >= 70 ? <CheckCircle2 size={18}/> : <AlertTriangle size={18}/>}
                            {percentage >= 70 ? 'Satisfactory Performance' : 'Academic Warning'}
                        </h4>
                        <p className={`text-sm ${percentage >= 70 ? 'text-emerald-700' : 'text-rose-700'}`}>
                            {percentage >= 70 
                                ? "You have demonstrated competency in the selected modules. Maintain current study habits." 
                                : "Performance falls below the departmental threshold. We recommend reviewing flagged topics in the Atlas immediately."}
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {hasMistakes ? (
                            <button onClick={retryIncorrectOnly} className="py-4 rounded-xl border-2 border-rose-100 bg-rose-50 text-rose-700 font-bold uppercase text-xs tracking-widest hover:bg-rose-100 transition-all flex items-center justify-center gap-2">
                                <RotateCcw size={16} /> Retry Mistakes
                            </button>
                        ) : (
                            <button onClick={retrySession} className="py-4 rounded-xl border-2 border-slate-100 bg-slate-50 text-slate-700 font-bold uppercase text-xs tracking-widest hover:bg-slate-100 transition-all flex items-center justify-center gap-2">
                                <RotateCcw size={16} /> Retake Exam
                            </button>
                        )}
                        <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="py-4 rounded-xl border-2 border-slate-200 bg-white text-slate-700 font-bold uppercase text-xs tracking-widest hover:border-slate-400 transition-all flex items-center justify-center gap-2">
                            <FileText size={16} /> Audit Answers
                        </button>
                    </div>

                    <button 
                        onClick={() => saveAndExit(false)}
                        className="w-full py-5 bg-slate-900 text-white rounded-xl font-bold uppercase text-xs tracking-widest hover:bg-slate-800 transition-all shadow-lg hover:shadow-xl"
                    >
                        Conclude Session & Return to Dashboard
                    </button>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW (Audit Mode) ---
  if (view === 'review') {
    return (
        <div className="h-full bg-slate-50 flex flex-col">
            <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                <h2 className="font-bold text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                    <FileText size={16} /> Audit Log
                </h2>
                <button onClick={() => setView('results')} className="text-xs font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900">
                    Return to Score
                </button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8 space-y-6">
                <div className="max-w-4xl mx-auto space-y-4">
                    {questions.map((q, i) => (
                        <div key={i} className={`bg-white rounded-2xl border p-6 md:p-8 shadow-sm ${q.userAnswer === q.correctOption ? 'border-emerald-100' : 'border-rose-100'}`}>
                            <div className="flex gap-4">
                                <span className={`text-sm font-mono font-bold pt-1 ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`}>Q{i+1}</span>
                                <div className="space-y-4 flex-1">
                                    <h3 className="font-medium text-slate-900 leading-snug text-lg" dangerouslySetInnerHTML={{__html: formatQuestionText(q.data.questionText)}} />

                                    {q.data.questionImage && (
                                        <div className="p-2 border border-slate-100 bg-slate-50 rounded-xl w-fit">
                                            <img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 rounded-lg" alt="ref" />
                                        </div>
                                    )}

                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm mt-4">
                                        <div className={`p-4 rounded-xl border ${q.userAnswer === q.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'}`}>
                                            <span className="block text-[10px] font-black uppercase opacity-60 mb-1">Your Selection</span>
                                            <span className="font-bold block" dangerouslySetInnerHTML={{__html: q.userAnswer || "No Answer"}} />
                                        </div>
                                        {q.userAnswer !== q.correctOption && (
                                            <div className="p-4 rounded-xl border bg-slate-50 border-slate-200 text-slate-900">
                                                <span className="block text-[10px] font-black uppercase opacity-60 mb-1">Correct Answer</span>
                                                <span className="font-bold block" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import InteractiveAtlas from './components/InteractiveAtlas';
import MobileNavigation from './components/MobileNavigation';
import { AppMode, Question } from './types';

// Import all available chapters
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';
import { questions as ch12 } from './hooks/data_ch12';
import { questions as ch13 } from './hooks/data_ch13';
import { questions as ch14 } from './hooks/data_ch14';
import { questions as ch15 } from './hooks/data_ch15';
import { questions as ch16 } from './hooks/data_ch16';
import { questions as ch17 } from './hooks/data_ch17';
// Import new extra diagram questions
import { questions as extraDiagrams } from './hooks/data_chapter_all'; 

import { Trash2, Activity, ChevronRight, Play } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  // PERSISTENCE: Load last mode or default to Flashcards
  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE EFFECTS
  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // --- ULTIMATE DATA ENGINE ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...extraDiagrams, // Include extra diagram questions
        ...userVault
    ];

    const categoryAnswerPools: Record<string, string[]> = {};
    sources.forEach(q => {
        if (!categoryAnswerPools[q.category]) categoryAnswerPools[q.category] = [];
        if (q.answerText && q.answerText.length < 120 && !q.answerText.toLowerCase().includes('all of the above')) {
            categoryAnswerPools[q.category].push(q.answerText);
        }
    });

    sources.forEach(q => {
        const isLowQuality = 
            q.questionText.includes('Part ') || 
            q.answerText.includes('Node ') || 
            (q.questionText.length < 5 && !q.questionImage);

        if (!seenIds.has(q.id) && !isLowQuality) {
            let finalOptions = q.options ? [...q.options] : [];

            const isTrueFalse = finalOptions.length === 2 && 
                                finalOptions.some(o => o.toLowerCase() === 'true') && 
                                finalOptions.some(o => o.toLowerCase() === 'false');

            if (isTrueFalse) {
                finalOptions = ['True', 'False'];
            } 
            else if (finalOptions.length < 2) {
                const pool = categoryAnswerPools[q.category] || [];
                const randomDistractors = pool
                    .filter(a => a !== q.answerText)
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [q.answerText, ...randomDistractors];
                if (finalOptions.length < 2) {
                    finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not visible"];
                }
            }

            if (!finalOptions.includes(q.answerText)) {
                finalOptions[0] = q.answerText;
            }

            finalOptions = Array.from(new Set(finalOptions));

            uniqueQuestions.push({ ...q, options: finalOptions });
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
