    if (!activeEntry) return;
    if (isSpeaking && speakingId === 'atlas-summary') {
        cancel();
    } else {
        const points = activeEntry.related.map((p, i) => {
            const label = p.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '').replace(/\??$/i, '');
            return `Point ${i + 1}: ${label}. ${p.answerText}`;
        }).join('. ');

        const fullText = `Structure Breakdown for ${activeEntry.title}. ${points}`;
        speak(fullText, 'atlas-summary');
    }
  };

