import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import InteractiveAtlas from './components/InteractiveAtlas';
import MobileNavigation from './components/MobileNavigation';
import { AppMode, Question } from './types';

// Import all available chapters
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';
import { questions as ch12 } from './hooks/data_ch12';
import { questions as ch13 } from './hooks/data_ch13';
import { questions as ch14 } from './hooks/data_ch14';
import { questions as ch15 } from './hooks/data_ch15';
import { questions as ch16 } from './hooks/data_ch16';
import { questions as ch17 } from './hooks/data_ch17';

import { Trash2, Activity, ChevronRight, Play, BookOpen } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  // PERSISTENCE: Load last mode or default to Flashcards
  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE EFFECTS
  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // --- ULTIMATE DATA ENGINE ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...userVault
    ];

    const categoryAnswerPools: Record<string, string[]> = {};
    sources.forEach(q => {
        if (!categoryAnswerPools[q.category]) categoryAnswerPools[q.category] = [];
        if (q.answerText && q.answerText.length < 120 && !q.answerText.toLowerCase().includes('all of the above')) {
            categoryAnswerPools[q.category].push(q.answerText);
        }
    });

    sources.forEach(q => {
        const isLowQuality = 
            q.questionText.includes('Part ') || 
            q.answerText.includes('Node ') || 
            (q.questionText.length < 5 && !q.questionImage);

        if (!seenIds.has(q.id) && !isLowQuality) {
            let finalOptions = q.options ? [...q.options] : [];

            const isTrueFalse = finalOptions.length === 2 && 
                                finalOptions.some(o => o.toLowerCase() === 'true') && 
                                finalOptions.some(o => o.toLowerCase() === 'false');

            if (isTrueFalse) {
                finalOptions = ['True', 'False'];
            } 
            else if (finalOptions.length < 2) {
                const pool = categoryAnswerPools[q.category] || [];
                const randomDistractors = pool
                    .filter(a => a !== q.answerText)
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [q.answerText, ...randomDistractors];
                if (finalOptions.length < 2) {
                    finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not visible"];
                }
            }

            if (!finalOptions.includes(q.answerText)) {
                finalOptions[0] = q.answerText;
            }

            finalOptions = Array.from(new Set(finalOptions));

            uniqueQuestions.push({ ...q, options: finalOptions });
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="min-h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
         <div className="absolute inset-0 bg-grid-pattern opacity-40 pointer-events-none"></div>

         <div className="relative z-10 flex flex-col items-center text-center space-y-10 max-w-xl w-full my-auto animate-fade-in">

            <div className="relative group cursor-pointer" onClick={() => setHasStarted(true)}>
                <div className="absolute inset-0 bg-rose-500/20 rounded-full blur-3xl transform scale-150 opacity-0 group-hover:opacity-100 transition-opacity duration-1000"></div>
                <div className="w-32 h-32 bg-white rounded-[2.5rem] shadow-2xl flex items-center justify-center border border-slate-100 relative z-10 transform group-hover:scale-105 transition-transform duration-500">
                   <Activity size={64} className="text-rose-600" strokeWidth={1.5} />
                </div>
            </div>

            <div className="space-y-4">
               <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/80 backdrop-blur-sm border border-slate-200 shadow-sm hover:shadow-md transition-shadow cursor-default">
                  <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">
                    Occupational Therapy Edition
                  </span>
               </div>

               <h1 className="text-5xl md:text-7xl font-black text-slate-900 tracking-tighter leading-[0.9] font-display">
                  Anatomy <br/> <span className="text-transparent bg-clip-text bg-gradient-to-r from-rose-600 to-amber-500">&</span> Physiology
               </h1>

               <p className="text-slate-500 font-medium text-lg leading-relaxed max-w-sm mx-auto text-balance">
                  A professional study suite designed for clinical mastery and board preparation.
               </p>
            </div>

            <div className="w-full flex flex-col items-center gap-8">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="group relative w-full max-w-xs py-5 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs shadow-xl hover:bg-rose-600 transition-all hover:-translate-y-1 active:scale-95 flex items-center justify-center gap-3 overflow-hidden"
                >
                     <span className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></span>
                     <span className="relative z-10 flex items-center gap-3">Enter Portal <ChevronRight size={16} /></span>
                </button>

                <div className="flex items-center gap-6 text-slate-400">
                    <div className="flex flex-col items-center gap-1">
                        <BookOpen size={20} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">1,100+ Cards</span>
                    </div>
                    <div className="w-px h-8 bg-slate-200"></div>
                    <div className="flex flex-col items-center gap-1">
                        <Activity size={20} />
                        <span className="text-[9px] font-bold uppercase tracking-widest">Clinical Mode</span>
                    </div>
                </div>
            </div>
         </div>

         <div className="absolute bottom-6 text-[10px] font-bold text-slate-300 uppercase tracking-widest">
            OT Department • V.5.2
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden fixed inset-0">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-4 md:pb-6 max-w-7xl px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full rounded-t-[2.5rem] md:rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/50 bg-white/60 backdrop-blur-xl relative z-10 transition-all duration-700 ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-28 md:pb-0">
                <Flashcards data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-28 md:pb-0">
                <InteractiveAtlas data={allQuestions} />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-28 md:pb-0">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-32 md:pb-6 animate-fade-in">
                <QuestionList 
                  data={allQuestions} 
                  onExport={() => {}} 
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors flex items-center gap-2">
                        <Trash2 size={12} /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
      />
    </div>
  );
};

export default App;

