import { useState, useEffect, useCallback, useRef } from 'react';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const utteranceRef = useRef<SpeechSynthesisUtterance | null>(null);

  const cancel = useCallback(() => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return;
    window.speechSynthesis.cancel();

    // Optimistically clear state
    if (utteranceRef.current) {
        // Remove listeners to prevent ghost state updates
        utteranceRef.current.onend = null;
        utteranceRef.current.onerror = null;
        utteranceRef.current = null;
    }
    setIsSpeaking(false);
    setSpeakingId(null);
  }, []);

  const speak = useCallback((text: string, id: string) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    // Toggle off if clicking the same button
    if (speakingId === id && isSpeaking) {
      cancel();
      return;
    }

    // Stop any current speech
    window.speechSynthesis.cancel();

    // Simple text cleaning
    const cleanText = text
      .replace(/<[^>]*>/g, '') // Remove HTML tags
      .replace(/&nbsp;/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    if (!cleanText) return;

    const utterance = new SpeechSynthesisUtterance(cleanText);
    utteranceRef.current = utterance;

    // Voice selection: prefer Google US English, Samantha, or any English default
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => 
      v.name.includes('Google US English') || 
      v.name.includes('Samantha') || 
      (v.lang.startsWith('en') && v.default)
    );
    if (preferredVoice) utterance.voice = preferredVoice;

    utterance.rate = 0.9; // Slightly slower for clarity
    utterance.pitch = 1.0;
    utterance.volume = 1.0;

    utterance.onstart = () => {
      setIsSpeaking(true);
      setSpeakingId(id);
    };

    utterance.onend = () => {
      setIsSpeaking(false);
      setSpeakingId(null);
      utteranceRef.current = null;
    };

    utterance.onerror = (e) => {
      // 99% of errors are "canceled" or "interrupted" when users click navigation buttons.
      // We silence these to prevent console spam and user confusion.
      if (e.error === 'interrupted' || e.error === 'canceled') {
        setIsSpeaking(false);
        setSpeakingId(null);
        return;
      }

      // Fix: Log the error property string instead of the event object to avoid [object Object]
      console.warn("Speech synthesis error:", e.error || 'Unknown error');
      setIsSpeaking(false);
      setSpeakingId(null);
    };

    try {
      window.speechSynthesis.speak(utterance);
    } catch (err) {
      // Safely log the error message
      console.error("Failed to start speech:", err instanceof Error ? err.message : String(err));
      setIsSpeaking(false);
      setSpeakingId(null);
    }

  }, [cancel, isSpeaking, speakingId]);

  // Load voices early
  useEffect(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
        const load = () => { window.speechSynthesis.getVoices(); };
        load();
        if (window.speechSynthesis.onvoiceschanged !== undefined) {
            window.speechSynthesis.onvoiceschanged = load;
        }
    }
    return () => {
        if (typeof window !== 'undefined' && window.speechSynthesis) {
            window.speechSynthesis.cancel();
        }
    };
  }, []);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId
  };
};

